// Multi-touch attribution engine
const items = $input.all();
const deals = items.filter(i => i.json.properties?.dealname).map(i => i.json);
const ga4Response = items.find(i => i.json.rows)?.json;

// Parse GA4 touchpoints
const touchpoints = {};
if (ga4Response?.rows) {
  ga4Response.rows.forEach(row => {
    const source = row.dimensionValues[0].value;
    const medium = row.dimensionValues[1].value;
    const campaign = row.dimensionValues[2].value;
    const key = `${source}/${medium}${campaign !== '(not set)' ? '/' + campaign : ''}`;
    const sessions = parseInt(row.metricValues[0].value);
    const conversions = parseInt(row.metricValues[1].value);
    touchpoints[key] = (touchpoints[key] || 0) + sessions;
  });
}

// Calculate attribution for each deal
const attributed = deals.map(deal => {
  const amount = parseFloat(deal.properties?.amount?.value || 0);
  const source = deal.properties?.hs_analytics_source?.value || 'direct';
  const source_data = deal.properties?.hs_analytics_source_data_1?.value || '';

  // Simple attribution models
  return {
    deal_id: deal.id,
    deal_name: deal.properties?.dealname?.value,
    amount,
    close_date: deal.properties?.closedate?.value,
    first_touch_channel: source,
    last_touch_channel: source_data || source,
    attributed_revenue_first: amount,
    attributed_revenue_last: amount,
    attributed_revenue_linear: amount
  };
});

// Aggregate by channel
const channel_totals = {};
attributed.forEach(d => {
  const ch = d.first_touch_channel;
  if (!channel_totals[ch]) channel_totals[ch] = { first_touch: 0, last_touch: 0, linear: 0, deals: 0 };
  channel_totals[ch].first_touch += d.attributed_revenue_first;
  channel_totals[ch].last_touch += d.attributed_revenue_last;
  channel_totals[ch].linear += d.attributed_revenue_linear;
  channel_totals[ch].deals += 1;
});

return [{ json: { attributed, channel_totals, total_deals: attributed.length, total_revenue: attributed.reduce((s,d) => s+d.amount, 0), run_date: new Date().toISOString() } }];

